// ─────────────────────────────────────────────────────────────────────────
// Answers. The knowledge base fills in here. An entry mints the question's
// own `/faq/<id>/` page and adds it to the FAQ structured data. Unanswered
// questions stay listed + searchable on the index until someone answers them.
// Keep answers accurate to the current public API; link a recipe/guide when
// one shows the behaviour end to end.

const ANSWERS: Record<string, { en: string; links?: FaqLink[] }> = {
  'basics-001': {
    en: 'Use the fluent `ReelSetBuilder`: chain `.reels()`, `.visibleRows()`, `.symbolSize()`, register your symbols, then `.build()` returns a `ReelSet` (a PixiJS `Container`) that you add to the stage.',
    links: [
      { label: 'Guide: Your first reelset', href: '/guides/your-first-reelset/' },
      { label: 'Recipe: Classic 5×3', href: '/recipes/classic-5x3/' },
    ],
  },
  'basics-002': {
    en: 'Set the column count with `.reels(n)` on the builder before `.build()`.',
  },
  'basics-003': {
    en: 'Use `.visibleRows(n)` for a uniform row count, or `.visibleRowsPerReel([...])` when each reel shows a different number of rows.',
  },
  'basics-006': {
    en: 'Seed the opening grid with `.initialFrame(grid)` on the builder, passing one `ColumnTarget` per reel — e.g. `{ visible: [\'A\', \'B\', \'C\'] }`.',
  },
  'symbols-006': {
    en: 'Pass relative weights to `.weights({ id: n })`: a higher number lands more often. A weight of `0` means the symbol never comes from random fill, so it can only be placed by the server / `setResult`.',
  },
  'spin-001': {
    en: 'Call `await reelSet.spin()`. It starts every reel with a staggered delay and resolves with a `SpinResult` once all reels have landed.',
    links: [{ label: 'Guide: Spin lifecycle', href: '/guides/spin-lifecycle/' }],
  },
  'spin-002': {
    en: 'Once the server responds, call `reelSet.setResult(grid)` while the spin promise is still pending. The stop sequence consumes it and each reel lands on its target.',
  },
  'spin-007': {
    en: 'On the second tap call `reelSet.skipSpin()` to slam the reels to their landing — or `reelSet.requestSkip()` if the server result has not arrived yet, which queues the slam for the moment it does.',
    links: [{ label: 'Recipe: Slam-stop', href: '/recipes/slam-stop/' }],
  },
  'spin-010': {
    en: 'Pass `reelSet.spin({ holdReels: [0, 4] })`. Held reels skip START / SPIN / STOP entirely, do not move, and count as already-landed for the all-landed resolver.',
    links: [{ label: 'Recipe: Hold & Win respin', href: '/recipes/hold-and-win/' }],
  },
  'result-001': {
    en: 'Give `reelSet.setResult(grid)` an array of one `ColumnTarget` per reel: `{ visible: [\'A\',\'B\',\'C\'], bufferAbove?: [...], bufferBelow?: [...] }`. The visible array is the on-screen window; the buffers target cells just outside it.',
  },
  'cascade-001': {
    en: 'Build with `.tumble(...)`, then after fading the winners call `reelSet.refill(winners, nextGrid)` with the cleared cells and the new symbols. Survivors fall into the gaps and fresh symbols drop in from above.',
    links: [{ label: 'Recipe: Cascade 6×5', href: '/recipes/cascade-6x5/' }],
  },
  'anim-004': {
    en: 'Override `playDestroy(opts)` on your `ReelSymbol`. The default is a ~320 ms scale / spin / fade implode; for Spine, play a `disintegration` or shatter track. Honour `opts.signal` so a slam can abort it mid-tween.',
  },
  'hw-001': {
    en: 'A Hold & Win cell is its own 1×1 ReelSet — the engine\'s atomic spin unit is the reel, the mechanic\'s is the cell. `HoldAndWinBuilder` (in `examples/shared/`) builds the whole grid of independent cells plus the lock / respin choreography. Copy it into your game and drive it with `enter()` then `respin()` per round.',
    links: [
      { label: 'Recipe: Hold & Win respin', href: '/recipes/hold-and-win/' },
      { label: 'Recipe: Hold & Win — Spine coins', href: '/recipes/hold-and-win-spine/' },
    ],
  },
  'hw-002': {
    en: 'Stop spinning that cell and leave its symbol in place. With `HoldAndWinBuilder` a hit cell simply is not respun next round; the `coin:locked` event fires so you can play the lock animation and update the HUD.',
  },
  'coins-005': {
    en: 'Land the coin showing a mystery face, then on lock spin a strip of candidate values inside the coin and ease it onto the real amount. Drive it from the `coin:locked` event via `symbolAt(cell)` so the board itself stays value-agnostic.',
    links: [{ label: 'Recipe: Hold & Win — mystery value coin', href: '/recipes/hold-and-win-mystery-coin/' }],
  },
  'coins-010': {
    en: 'The collector is just another server-placed id. When it locks, walk the locked coins and fly a clone of each value into the collector along a bezier arc (`bezierFly`), ticking the collector\'s total up on every arrival.',
    links: [
      { label: 'Recipe: Hold & Win — collector', href: '/recipes/hold-and-win-collector/' },
      { label: 'Recipe: Hold & Win — collector with particles', href: '/recipes/hold-and-win-collector-particles/' },
    ],
  },
  'chars-002': {
    en: 'Read the source cell center with `board.cellCenter(cell)` and the character\'s position, then tween a coin clone along a bezier arc with `bezierFly(from, to, { lean: \'up\' })`. Play the character\'s reaction on arrival. The flight is game-layer choreography; the board only hands out pixel geometry and events.',
    links: [{ label: 'Recipe: Hold & Win — collector', href: '/recipes/hold-and-win-collector/' }],
  },
  'basics-004': { en: '`.symbolSize(width, height)` on the builder sets the pixel box of one cell; pair it with `.symbolGap(x, y)` for spacing.' },
  'basics-005': { en: '`.symbolGap(x, y)` sets the pixel gap between reels (x) and between rows (y).' },
  'basics-007': { en: 'Inside `.symbols((r) => …)`, call `r.register(id, SymbolClass, options)` once per symbol id your game uses.', links: [{ label: 'Guide: Symbols', href: '/guides/symbols/' }] },
  'basics-008': { en: 'Build with `.initialFrame(grid)` and simply never call `spin()` — the board renders the seeded symbols statically.' },
  'basics-009': { en: '`build()` returns a `ReelSet`, which is a PixiJS `Container`: `app.stage.addChild(reelSet)`, and pass the app ticker via `.ticker(app.ticker)`.' },
  'basics-010': { en: 'A `ReelSet` is a Container with normal `width`/`height`, so set `reelSet.x`/`reelSet.y` to `(app.screen.width - reelSet.width) / 2`, etc.' },
  'basics-011': { en: 'Set `reelSet.scale` from the ratio of available space to `reelSet.width`/`height`, and recompute it on the renderer `resize` event.' },
  'basics-012': { en: 'Use `reelSet.setResult(grid)` (animated, through a spin) or `reelSet.setSymbolAt(col, row, id)` for an instant in-place swap while the reels are idle.' },
  'basics-013': { en: 'Pass your ticker with `.ticker(myTicker)` — the engine drives all motion from it — and call `driveGsapWithTicker(ticker)` so GSAP advances off the same clock.' },
  'basics-014': { en: '`reelSet.destroy()` tears down the reels, pools, masks and ticker refs (every subsystem implements `Disposable`).' },
  'symbols-001': { en: 'Subclass `ReelSymbol`, implement `onActivate` / `resize` / `playWin` / `stopAnimation`, then register it with `r.register(id, MySymbol, opts)`.', links: [{ label: 'Guide: Symbols', href: '/guides/symbols/' }] },
  'symbols-002': { en: 'Use the built-in `SpriteSymbol`: `r.register(id, SpriteSymbol, { textures })` maps each id to a `Texture`.', links: [{ label: 'Recipe: Texture-atlas symbols', href: '/recipes/texture-atlas-symbols/' }] },
  'symbols-003': { en: 'Use `AnimatedSpriteSymbol` with `{ frames: Record<id, Texture[]>, animationSpeed }`; the board calls `playWin()` to play the sequence.', links: [{ label: 'Recipe: Hold & Win — sprite coins', href: '/recipes/hold-and-win-sprites/' }] },
  'symbols-004': { en: 'Use `SpineSymbol` (or `SpineReelSymbol`) from `pixi-reels/spine` with a `skeletonDataMap` / `spineMap`.', links: [{ label: 'Recipe: Big symbols with Spine', href: '/recipes/spine-big-symbols/' }] },
  'symbols-005': { en: 'Register the `EmptySymbol` class against an id like `empty` — it renders nothing but still occupies the slot.', links: [{ label: 'Recipe: EmptySymbol', href: '/recipes/empty-symbol/' }] },
  'symbols-007': { en: 'Give it a small number in `.weights({ rare: 1, common: 20 })`, or `0` so it never comes from random fill (server-placed only).' },
  'symbols-008': { en: 'Pass `anchor` in the symbol options (e.g. `SpriteSymbol`\'s `{ anchor: { x: 0.5, y: 0.5 } }`); SpriteSymbol defaults to top-left, Spine centers in `resize()`.' },
  'symbols-009': { en: 'Implement `resize(width, height)` on your `ReelSymbol` and put all positioning there — it is called on every symbol swap, so the constructor is the wrong place.', links: [{ label: 'Guide: Symbols', href: '/guides/symbols/' }] },
  'symbols-010': { en: 'Use the shared `BlurSpriteSymbol` (`{ textures, blurTextures }`); subclass it to swap on the engine\'s `onReelSpinStart` / `onReelLanded` hooks so blur needs no per-cell event wiring.', links: [{ label: 'Recipe: Hold & Win — sprite coins', href: '/recipes/hold-and-win-sprites/' }] },
  'symbols-011': { en: 'Pass per-instance data through the symbol\'s constructor options, or carry it in a pin payload via `reelSet.pin(col, row, id, { payload })`.', links: [{ label: 'Recipe: Value-carrying coin', href: '/recipes/value-coin-pin/' }] },
  'symbols-012': { en: '`reelSet.getVisibleGrid()` returns the whole `string[][]`, or read the live instance with `reelSet.getReel(col).getSymbolAt(row)`.' },
  'symbols-013': { en: 'Mark the id `{ unmask: true }` via `.symbolData(...)` so the engine reparents its view to the viewport\'s unmasked container, above the reel mask (server-placed ids only).' },
  'symbols-014': { en: 'Register both ids with the same class and point them at the same texture / skeleton in the options map.' },
  'symbols-015': { en: 'Tint the symbol\'s `view` (a PixiJS Container) in `onActivate` — e.g. set `this.view.tint` for a charged state.' },
  'spin-003': { en: '`await reelSet.spin()` resolves with a `SpinResult` once every reel lands, or listen for the `spin:complete` event.', links: [{ label: 'Guide: Spin lifecycle', href: '/guides/spin-lifecycle/' }] },
  'spin-004': { en: 'The active `SpeedProfile`\'s `spinDelay` staggers reel starts; tune it per profile via `.speed(name, { …, spinDelay })`.', links: [{ label: 'Guide: Speed modes', href: '/guides/speed-modes/' }] },
  'spin-005': { en: '`reelSet.setDropOrder(\'ltr\')` (also `\'rtl\'` / `\'all\'` / a delays array) sets stop order; the profile\'s `stopDelay` is the gap.' },
  'spin-006': { en: 'Register a faster profile (`.speed(\'turbo\', SpeedPresets.TURBO)`) and switch with `reelSet.setSpeed(\'turbo\')`.', links: [{ label: 'Guide: Speed modes', href: '/guides/speed-modes/' }] },
  'spin-008': { en: 'The first `skipSpin()` boosts the in-flight spin\'s speed (it emits `skip:boosted`) without changing your selected profile; the next round restores it.' },
  'spin-009': { en: 'Tune `bounceDistance` and `bounceDuration` on the `SpeedProfile`.' },
  'spin-011': { en: 'Hold the rest: `reelSet.spin({ holdReels: [everything but one] })`. For a fully self-contained single reel, the Hold & Win pattern uses one 1×1 ReelSet per cell.', links: [{ label: 'Recipe: Hold & Win respin', href: '/recipes/hold-and-win/' }] },
  'spin-012': { en: 'Pass an `AbortSignal` via `spin({ signal })` and call `controller.abort()`; the spin promise rejects with an AbortError.', links: [{ label: 'Recipe: Nudge abort', href: '/recipes/nudge-abort/' }] },
  'spin-013': { en: 'Gate the spin button on the `spin()` promise (and any post-land animation promises) before calling `spin()` again.' },
  'spin-014': { en: 'Pass `spin({ timeoutMs })` (or a `signal`) — if `setResult` never arrives, the spin rejects so you can surface an error.' },
  'spin-015': { en: 'Drive the engine from `app.ticker` and call `driveGsapWithTicker(app.ticker)` so GSAP advances off the Pixi ticker instead of rAF, which freezes on hidden tabs.' },
  'result-002': { en: 'Call `reelSet.setResult(grid)` with the exact `ColumnTarget[]` you want; with the test harness, `CheatEngine` + `forceGrid(grid)` forces it every spin.', links: [{ label: 'Guide: Cheats & testing', href: '/guides/cheats-and-testing/' }] },
  'result-003': { en: '`reelSet.getVisibleGrid()` returns the resolved visible `string[][]` (also on `SpinResult.symbols`).' },
  'result-004': { en: 'Map the server payload to `ColumnTarget[]` and pass it to `reelSet.setResult(grid)` while the spin promise is still pending.', links: [{ label: 'Recipe: Classic 5×3', href: '/recipes/classic-5x3/' }] },
  'result-005': { en: 'Put the symbol in that reel\'s `bufferAbove`, e.g. `{ visible: [...], bufferAbove: [\'COIN\'] }`.', links: [{ label: 'Guide: Buffer indexing', href: '/guides/buffer-indexing/' }] },
  'result-006': { en: 'Anchor a tall block in `bufferAbove` so only its tail shows at row 0; the viewport mask clips the off-screen part.', links: [{ label: 'Recipe: Big-symbol partial land', href: '/recipes/big-symbol-partial-land/' }] },
  'result-007': { en: 'Inject a deterministic generator with `.rng(fn)` on the builder — the shared `SeededRng` works.', links: [{ label: 'Guide: Cheats & testing', href: '/guides/cheats-and-testing/' }] },
  'result-008': { en: 'Place it explicitly in the `ColumnTarget` you pass to `setResult`, or use `CheatEngine`\'s `forceScatters` / `forceCell`.', links: [{ label: 'Guide: Cheats & testing', href: '/guides/cheats-and-testing/' }] },
  'result-009': { en: 'Build with `.multiways({ minRows, maxRows })` and pass a per-reel `ColumnTarget[]` whose `visible` arrays differ in length.', links: [{ label: 'Guide: MultiWays', href: '/guides/multiways/' }] },
  'result-010': { en: 'Use the explicit `ColumnTarget` object form (`{ visible, bufferAbove, bufferBelow }`) — it survives JSON / postMessage, unlike the negative-index array form.', links: [{ label: 'Guide: Buffer indexing', href: '/guides/buffer-indexing/' }] },
  'result-011': { en: 'Keep payout math on the server; the engine only consumes the visual grid via `setResult` and never computes wins itself.' },
  'result-012': { en: 'Re-inject the same `.rng(seed)` and the same `setResult` grid; the debug recorder (`startRecording()` / `getFrames()`) captures a spin frame by frame.', links: [{ label: 'Guide: Debugging', href: '/guides/debugging/' }] },
  'motion-001': { en: 'Make the spin a drop-in: build with `.tumble({ dropIn })` and spin `{ mode: \'cascade\' }`, or register `ImmediateMode` for an instant land.', links: [{ label: 'Recipe: Tumble feels', href: '/recipes/tumble-feels/' }] },
  'motion-002': { en: 'The stop phase bounces by `bounceDistance` / `bounceDuration` on the active `SpeedProfile`.' },
  'motion-003': { en: '`.tumble({ dropIn: { rowStagger } })` delays each symbol\'s fall; the `cascade:dropIn:symbol` events expose per-symbol timing.', links: [{ label: 'Recipe: Fall delays', href: '/recipes/fall-delays/' }] },
  'motion-004': { en: 'Upward roll-up is not a built-in direction flag — drive it as a cascade drop-in variant or your own GSAP on each symbol `view`; the strip spin itself is downward.' },
  'motion-005': { en: 'Per-reel spin direction is not a built-in flag today; mix it by driving specific reels with a custom `SpinningMode` or your own motion on those reels.' },
  'motion-006': { en: 'Pre-fill the `bufferAbove` slot so a teaser symbol sits just out of frame and scrolls into view on the next spin.', links: [{ label: 'Recipe: Peek from above', href: '/recipes/peek-from-above/' }] },
  'motion-007': { en: '`reelSet.nudge(col, { … })` shifts a reel up or down after it landed, feeding caller-supplied incoming symbols.', links: [{ label: 'Recipe: Nudge', href: '/recipes/nudge/' }] },
  'motion-008': { en: 'MultiWays changes a reel\'s visible row count per spin (via `setShape` + the AdjustPhase); a permanent static row change otherwise needs a rebuild.', links: [{ label: 'Guide: MultiWays', href: '/guides/multiways/' }] },
  'motion-009': { en: 'Adding whole columns mid-feature (Infinity Reels) is not built in — the reel count is fixed at build; it is a custom extension on top of the engine.' },
  'motion-010': { en: 'Orientation is vertical-only in the engine today; a horizontal board is a custom layout, not a builder flag.' },
  'motion-011': { en: 'Two symbols per cell is not a built-in; render a composite `ReelSymbol` whose `view` holds both halves.' },
  'motion-012': { en: 'Big-symbol blocks stay intact through spins and cascades automatically — you place the anchor and the engine paints OCCUPIED across the rest of the block.', links: [{ label: 'Recipe: Big-symbol cascade fall', href: '/recipes/big-symbol-cascade-fall/' }] },
  'antic-001': { en: '`reelSet.setAnticipation([reelIndex])` before it stops slows that reel using the profile\'s `anticipationDelay`.', links: [{ label: 'Recipe: Anticipate a reel', href: '/recipes/anticipate-a-reel/' }] },
  'antic-002': { en: 'Track landed scatters from `spin:reelLanded`, then call `setAnticipation([next])` only once the count crosses your threshold.' },
  'antic-003': { en: 'Land N-1 scatters plus `setAnticipation` on the reel that almost completes, and place the teased scatter in `bufferAbove`.', links: [{ label: 'Recipe: Near-miss', href: '/recipes/near-miss/' }] },
  'antic-004': { en: 'Listen for `spin:stopping` (or your own anticipation-start hook) and play the glow/sound; `setAnticipation` already slowed the reel.' },
  'antic-005': { en: '`setAnticipation([...])` extends those reels via `anticipationDelay`; for finer control raise their `minimumSpinTime`.', links: [{ label: 'Recipe: Anticipation teaser', href: '/recipes/anticipation-teaser/' }] },
  'antic-006': { en: 'Prefill the teased symbol into `bufferAbove` so it scrolls into view on the slowed reel, then settles back.', links: [{ label: 'Recipe: Anticipation teaser', href: '/recipes/anticipation-teaser/' }] },
  'antic-007': { en: 'In Hold & Win, flip the remaining cells to a tension profile with the builder\'s `anticipateWhen(({ locked, capacity }) => capacity - locked === 1)`.', links: [{ label: 'Recipe: Hold & Win — last-cell anticipation', href: '/recipes/hold-and-win-anticipation/' }] },
  'antic-008': { en: 'Call `setAnticipation` with several reel indices; each slows in turn for rolling tension.', links: [{ label: 'Recipe: Near-miss', href: '/recipes/near-miss/' }] },
  'antic-009': { en: 'Anticipation is just the slow stop — if the tease misses, the reel lands normally, so there is nothing to cancel; stop your own glow/sound on `spin:reelLanded`.' },
  'antic-010': { en: 'Use a profile whose `accelerationEase` / `decelerationEase` ramps up before the anticipation slowdown; tune `accelerationDuration`.' },
  'antic-011': { en: 'Hold & Win cells are independent reels, so the builder\'s `anticipateWhen(...)` runs anticipation on the still-spinning cells out of the box; for one cell, swap that mini-reel to a tension profile.', links: [{ label: 'Recipe: Hold & Win — last-cell anticipation', href: '/recipes/hold-and-win-anticipation/' }] },
  'wins-001': { en: '`reelSet.spotlight.show(positions)` dims the board and promotes the winning cells, or use the higher-level `WinPresenter`.', links: [{ label: 'Guide: Win animations', href: '/guides/win-animations/' }] },
  'wins-002': { en: 'Core never draws lines — subscribe to `win:group` and draw your own overlay using `reelSet.getCellBounds(col, row)`.', links: [{ label: 'Recipe: Paylines (events only)', href: '/recipes/paylines-events-only/' }] },
  'wins-003': { en: '`WinPresenter` calls each winning symbol\'s `playWin()`; or call it yourself on `reelSet.getReel(col).getSymbolAt(row)`.', links: [{ label: 'Guide: Win animations', href: '/guides/win-animations/' }] },
  'wins-004': { en: 'Read the winning cells from `win:group` and spotlight them with `SymbolSpotlight.show(positions)` — no line geometry needed.', links: [{ label: 'Recipe: Paylines (events only)', href: '/recipes/paylines-events-only/' }] },
  'wins-005': { en: '`reelSet.spotlight.cycle(lines)` (or `WinPresenter` with a `cycles` count) steps through each winning line in turn.', links: [{ label: 'Recipe: Cascade WinPresenter', href: '/recipes/cascade-winpresenter/' }] },
  'wins-006': { en: 'Draw the links yourself between cluster cells using `getCellBounds`; the engine supplies geometry, you supply the lines.', links: [{ label: 'Recipe: Cell bounds', href: '/recipes/cell-bounds/' }] },
  'wins-007': { en: 'Evaluate both directions in your win logic and feed all winning cells to the presenter — the engine is direction-agnostic.' },
  'wins-008': { en: 'Pick the tier from the win amount in your code and play the matching celebration; the engine exposes the win cells, the banner is game-layer.', links: [{ label: 'Guide: Win animations', href: '/guides/win-animations/' }] },
  'wins-009': { en: 'Drive your own counter widget; the shared `roundBus` (`win:set` / `win:add`) is a ready-made event bus for a running win total.' },
  'wins-010': { en: 'Scale `reelSet` (a Container) with a GSAP tween for the zoom, and build the banner in your UI layer.' },
  'wins-011': { en: '`WinPresenter.abort()` (or `spotlight.abort()`) ends the in-flight presentation immediately.', links: [{ label: 'Guide: Win animations', href: '/guides/win-animations/' }] },
  'wins-012': { en: 'Both fire from the same `win:group` event — start the sound in the same listener that triggers the highlight.' },
  'cascade-002': { en: '`reelSet.runCascade({ … })` runs the full detect → destroy → refill loop until there are no new wins.', links: [{ label: 'Recipe: Cascade 6×5', href: '/recipes/cascade-6x5/' }] },
  'cascade-003': { en: 'Override `playDestroy(opts)` on the symbol; `reelSet.destroySymbols(cells)` plays it on the cleared cells.', links: [{ label: 'Recipe: Remove symbol', href: '/recipes/remove-symbol/' }] },
  'cascade-004': { en: '`reelSet.refill({ winners, grid })` slides survivors into the gaps and drops new symbols in from above.', links: [{ label: 'Recipe: Cascade 6×5', href: '/recipes/cascade-6x5/' }] },
  'cascade-005': { en: '`.tumble({ fall: { rowStagger } })` plus the refill order set the per-column timing.', links: [{ label: 'Recipe: Refill orders', href: '/recipes/refill-orders/' }] },
  'cascade-006': { en: 'Listen for `cascade:chain:start` / `cascade:chain:end` and bump your multiplier each chain; the meter itself is game-layer.', links: [{ label: 'Recipe: Cascade 6×5', href: '/recipes/cascade-6x5/' }] },
  'cascade-007': { en: 'Detect 8+ connected in your win logic and feed the winners to `runCascade` / `refill`; the engine tumbles whatever cells you clear.', links: [{ label: 'Recipe: Cascade 6×5', href: '/recipes/cascade-6x5/' }] },
  'cascade-008': { en: 'Track orb values across the tumble via the cascade events and apply the sum on the final `cascade:chain:end`.', links: [{ label: 'Recipe: Tumble anticipation', href: '/recipes/tumble-anticipation/' }] },
  'cascade-009': { en: 'One ReelSet, override the mode per spin: classic strip-spin first, then `spin({ mode: \'cascade\' })` for the refills.', links: [{ label: 'Recipe: Spin then cascade', href: '/recipes/spin-then-cascade/' }] },
  'cascade-010': { en: 'Pin it with `reelSet.pin(col, row, id)` so it sticks while the cascade clears around it.', links: [{ label: 'Recipe: Sticky-win respin', href: '/recipes/sticky-win-respin-pin/' }] },
  'cascade-011': { en: 'Run `WinPresenter.show(wins)` inside your cascade loop, between `destroySymbols` and `refill`.', links: [{ label: 'Recipe: Cascade WinPresenter', href: '/recipes/cascade-winpresenter/' }] },
  'cascade-012': { en: '`reelSet.skipSpin()` during a cascade fast-forwards the remaining tumble steps.', links: [{ label: 'Recipe: Slam-stop', href: '/recipes/slam-stop/' }] },
  'cascade-013': { en: '`.tumble(...)` plus `setDropOrder` choose which column refills first — simultaneous, LTR wave, bottom-up, or top-down.', links: [{ label: 'Recipe: Refill orders', href: '/recipes/refill-orders/' }] },
  'wilds-001': { en: 'Pin it: `reelSet.pin(col, row, \'wild\', { turns })` keeps it across spins.', links: [{ label: 'Recipe: Sticky wild (CellPin)', href: '/recipes/sticky-wild-pin/' }] },
  'wilds-002': { en: 'On land, pin every cell of the column to wild for N turns; it auto-expires on the turn counter.', links: [{ label: 'Recipe: Expanding wild (CellPin)', href: '/recipes/expanding-wild-pin/' }] },
  'wilds-003': { en: '`reelSet.movePin(fromCol, fromRow, toCol, toRow)` shifts the wild one reel each respin with a flight.', links: [{ label: 'Recipe: Walking wild (CellPin)', href: '/recipes/walking-wild-pin/' }] },
  'wilds-004': { en: 'Carry the multiplier in the pin payload and render a ×N badge on the cell.', links: [{ label: 'Recipe: Multiplier wild (CellPin)', href: '/recipes/multiplier-wild-pin/' }] },
  'wilds-005': { en: 'Inject them with a `FrameMiddleware` (or place them in the `setResult` grid) before the reels stop.', links: [{ label: 'Recipe: Feature mode swap', href: '/recipes/feature-mode-swap/' }] },
  'wilds-006': { en: 'Pick the symbol at feature start and pin its whole column to wild — the same expanding-wild pin pattern.', links: [{ label: 'Recipe: Expanding wild (CellPin)', href: '/recipes/expanding-wild-pin/' }] },
  'wilds-007': { en: 'Pin with `{ turns: N }`; it auto-unpins and fires `pin:expired` when the counter runs out.', links: [{ label: 'Recipe: Sticky wild (CellPin)', href: '/recipes/sticky-wild-pin/' }] },
  'wilds-008': { en: 'Keep each wild\'s multiplier in its pin payload and multiply the payloads together in your win math.', links: [{ label: 'Recipe: Multiplier wild (CellPin)', href: '/recipes/multiplier-wild-pin/' }] },
  'wilds-009': { en: 'On `win:group`, pin a new wild at the cleared cell before the next cascade step.', links: [{ label: 'Recipe: Sticky-win respin', href: '/recipes/sticky-win-respin-pin/' }] },
  'wilds-010': { en: 'Use `movePin` to walk it and pin a multiplier payload at each cell it leaves behind.', links: [{ label: 'Recipe: Walking wild (CellPin)', href: '/recipes/walking-wild-pin/' }] },
  'wilds-011': { en: '`movePin` animates the wild between cells; chain the calls to follow a path.', links: [{ label: 'Recipe: Walking wild (CellPin)', href: '/recipes/walking-wild-pin/' }] },
  'wilds-012': { en: 'Pin every cell of that reel to wild for the feature\'s duration.', links: [{ label: 'Recipe: Expanding wild (CellPin)', href: '/recipes/expanding-wild-pin/' }] },
  'pins-001': { en: '`reelSet.pin(col, row, id)` locks the cell to that symbol so it survives spins.', links: [{ label: 'Guide: Pins', href: '/guides/pins/' }] },
  'pins-002': { en: '`reelSet.unpin(col, row)` removes it.', links: [{ label: 'Guide: Pins', href: '/guides/pins/' }] },
  'pins-003': { en: '`reelSet.pin(col, row, id, { turns: N })` auto-expires after N spins (also `\'eval\'` or `\'permanent\'`).', links: [{ label: 'Guide: Pins', href: '/guides/pins/' }] },
  'pins-004': { en: 'Pass `{ payload }` to `pin(...)` and read it back from `reelSet.getPin(col, row).payload`.', links: [{ label: 'Recipe: Multiplier wild', href: '/recipes/multiplier-wild-pin/' }] },
  'pins-005': { en: '`reelSet.pins` is a ReadonlyMap of every active pin.', links: [{ label: 'Guide: Pins', href: '/guides/pins/' }] },
  'pins-006': { en: '`reelSet.movePin(fromCol, fromRow, toCol, toRow, { duration, easing })` flies the pin to a new cell.', links: [{ label: 'Recipe: Walking wild (CellPin)', href: '/recipes/walking-wild-pin/' }] },
  'pins-007': { en: 'Pins clamp and restore automatically across MultiWays reshapes; `pin:migrated` fires when they move.', links: [{ label: 'Recipe: Sticky wild + MultiWays', href: '/recipes/sticky-wild-multiways/' }] },
  'pins-008': { en: 'Pin with `{ migration: \'origin\', originRow }` so it restores toward its origin row when the shape grows back.', links: [{ label: 'Recipe: Sticky wild + MultiWays', href: '/recipes/sticky-wild-multiways/' }] },
  'pins-009': { en: 'Pinned cells are overlaid onto the result before the stop sequencer, so they always land on the pin id regardless of the server grid.', links: [{ label: 'Guide: Pins', href: '/guides/pins/' }] },
  'pins-010': { en: 'Give the pinned symbol class its own `playWin` / landing animation, or react to the `pin:placed` event.', links: [{ label: 'Guide: Pins', href: '/guides/pins/' }] },
  'big-001': { en: 'Register the id with `size: { w: 2, h: 2 }` (weight 0), place its anchor cell via `setResult`, and the engine paints OCCUPIED across the block.', links: [{ label: 'Recipe: Big symbols (N×M)', href: '/recipes/big-symbols-mxn/' }] },
  'big-002': { en: 'Same mechanic with `size: { w: 3, h: 3 }`; use `SharedRectMaskStrategy` so the block is not clipped per reel.', links: [{ label: 'Recipe: Big symbols (N×M)', href: '/recipes/big-symbols-mxn/' }] },
  'big-003': { en: 'Register the id with `size: { w: 1, h: 3 }`.', links: [{ label: 'Recipe: Big symbols (N×M)', href: '/recipes/big-symbols-mxn/' }] },
  'big-004': { en: 'Give it `weight: 0` so it only ever comes from `setResult` / the server, never random fill.', links: [{ label: 'Recipe: Big symbols (N×M)', href: '/recipes/big-symbols-mxn/' }] },
  'big-005': { en: 'Anchor the tall block in `bufferAbove` so only its bottom cell shows at row 0.', links: [{ label: 'Recipe: Big-symbol partial land', href: '/recipes/big-symbol-partial-land/' }] },
  'big-006': { en: 'Render the symbol at the block size (e.g. a Spine `scale`) so it fills the whole N×M, not just the anchor cell.', links: [{ label: 'Recipe: Big symbols with Spine', href: '/recipes/spine-big-symbols/' }] },
  'big-007': { en: 'Land the block, then `spin({ holdReels: [its reels] })` so it survives the respin.', links: [{ label: 'Recipe: Big-symbol held respin', href: '/recipes/big-symbol-held-respin/' }] },
  'big-008': { en: 'The cascade carries the block as a unit — its tail falls through the strip into full view.', links: [{ label: 'Recipe: Big-symbol cascade fall', href: '/recipes/big-symbol-cascade-fall/' }] },
  'big-009': { en: 'After the win, swap the block id for single ids via `setSymbolAt` or the next `setResult`.' },
  'big-010': { en: '`reelSet.getBlockBounds(col, row)` returns the pixel rect of the whole block for an overlay.', links: [{ label: 'Recipe: Get block bounds', href: '/recipes/get-block-bounds/' }] },
  'big-011': { en: 'Buffer-anchored blocks that run past the top or bottom are clipped by the viewport mask automatically.', links: [{ label: 'Recipe: Big-symbol partial land', href: '/recipes/big-symbol-partial-land/' }] },
  'mways-001': { en: 'Build with `.multiways({ minRows, maxRows })` and pass per-reel `visible` arrays of different lengths to `setResult`.', links: [{ label: 'Guide: MultiWays', href: '/guides/multiways/' }] },
  'mways-002': { en: '`.multiways({ minRows, maxRows, reelPixelHeight })`.', links: [{ label: 'Guide: MultiWays', href: '/guides/multiways/' }] },
  'mways-003': { en: 'Ways = the product of the per-reel row counts; read the shape from `getVisibleGrid()` lengths or your result.', links: [{ label: 'Guide: MultiWays', href: '/guides/multiways/' }] },
  'mways-004': { en: 'Call `setShape(rowsPerReel)` before the spin; the AdjustPhase tweens each reel from its current rows to the target.', links: [{ label: 'Guide: MultiWays', href: '/guides/multiways/' }] },
  'mways-005': { en: '`.multiways({ reelPixelHeight })` fixes the reel\'s pixel box, so symbols resize to fit whatever row count lands.', links: [{ label: 'Guide: MultiWays', href: '/guides/multiways/' }] },
  'mways-006': { en: 'Combine `.multiways(...)` with `.tumble(...)`; the refills are shape-aware per reel.', links: [{ label: 'Recipe: MultiWays cascade', href: '/recipes/multiways-cascade/' }] },
  'mways-007': { en: 'An extra horizontal top strip is not a built-in; add it as a separate small ReelSet above the board.' },
  'mways-008': { en: 'For a fixed jagged shape use `.visibleRowsPerReel([...])` instead of MultiWays.', links: [{ label: 'Recipe: Pyramid shape', href: '/recipes/pyramid-shape/' }] },
  'mways-009': { en: 'Use `setAnticipation` on the reel about to grow; the AdjustPhase plays after it lands.', links: [{ label: 'Guide: MultiWays', href: '/guides/multiways/' }] },
  'mways-010': { en: 'They coexist, but the engine throws if a big symbol would straddle a reshaping reel — keep big symbols off MultiWays reels.', links: [{ label: 'Guide: Big symbols', href: '/guides/big-symbols/' }] },
  'hw-003': { en: '`board.respin(hits)` spins only the free cells; the locked ones sit out automatically.', links: [{ label: 'Recipe: Hold & Win respin', href: '/recipes/hold-and-win/' }] },
  'hw-004': { en: 'The builder\'s `.respins(3)` sets the count, and every locked coin resets it (the `respins:changed` reason is `\'hit-reset\'`).', links: [{ label: 'Recipe: Hold & Win respin', href: '/recipes/hold-and-win/' }] },
  'hw-005': { en: 'A respin with no hits decrements the counter automatically (`respins:changed` reason `\'miss\'`).', links: [{ label: 'Recipe: Hold & Win respin', href: '/recipes/hold-and-win/' }] },
  'hw-006': { en: '`board.respin(...)` returns `{ full, done }` and fires `board:full` when every cell is locked.', links: [{ label: 'Recipe: Hold & Win respin', href: '/recipes/hold-and-win/' }] },
  'hw-007': { en: '`board.enter(seedCoins)` seeds them already locked and fills the respin counter.', links: [{ label: 'Recipe: Hold & Win — Spine coins', href: '/recipes/hold-and-win-spine/' }] },
  'hw-008': { en: 'Read `board.lockedCoins.length` / `board.respinsLeft` (or the `coin:locked` / `respins:changed` events) into your HUD.', links: [{ label: 'Recipe: Hold & Win respin', href: '/recipes/hold-and-win/' }] },
  'hw-009': { en: 'Weight `empty` heavily over the coin on the strip, e.g. `.weights({ coin: 1, empty: 3 })`.', links: [{ label: 'Recipe: Hold & Win respin', href: '/recipes/hold-and-win/' }] },
  'hw-010': { en: 'Loop `await board.respin(round.hits)` per round with the server\'s hit list until `result.done`.', links: [{ label: 'Recipe: Hold & Win respin', href: '/recipes/hold-and-win/' }] },
  'hw-011': { en: 'For whole-column holds use one ReelSet and `spin({ holdReels })` instead of the per-cell board.', links: [{ label: 'Recipe: Hold & Win respin', href: '/recipes/hold-and-win/' }] },
  'hw-012': { en: 'Hide the base ReelSet and show the `HoldAndWinBoard.container` — same screen, two display objects; `enter(triggerCoins)` carries the trigger into the feature, and `feature:end` is when you swap back.', links: [{ label: 'Recipe: Hold & Win — enter from the base game', href: '/recipes/hold-and-win-base-to-feature/' }] },
  'hw-013': { en: 'On replay, `board.reset()` blanks the board, then re-`enter(seed)`; animate the sweep yourself.', links: [{ label: 'Recipe: Hold & Win — collector', href: '/recipes/hold-and-win-collector/' }] },
  'hw-014': { en: 'Collect each lock effect\'s promise and `await Promise.all(...)` before the next `board.respin(...)`.', links: [{ label: 'Recipe: Hold & Win — collector', href: '/recipes/hold-and-win-collector/' }] },
  'hw-015': { en: 'Check the locked cells for a full row in your `coin:locked` handler, flash the row and award the mini jackpot in the game layer.', links: [{ label: 'Recipe: Hold & Win — row-complete jackpot', href: '/recipes/hold-and-win-row-jackpot/' }] },
  'hw-016': { en: 'Live row growth is not built into the board; rebuild it at the new size, or pre-size it and reveal a row on the trigger.' },
  'hw-017': { en: 'On `coin:locked`, walk the other coins and bump their ids/data — the board hands you `symbolAt(cell)` and the coin payload.', links: [{ label: 'Recipe: Hold & Win — payer / doubler coin', href: '/recipes/hold-and-win-payer-coin/' }] },
  'hw-018': { en: 'Store the locked coins server-side and replay them into `board.enter(...)` on reload.' },
  'hw-019': { en: 'One `HoldAndWinBuilder` builds a board per tier — call `.build()` with different `.respins` / weights, or rebuild per bet.', links: [{ label: 'Recipe: Hold & Win respin', href: '/recipes/hold-and-win/' }] },
  'hw-020': { en: 'Each cell is its own 1×1 ReelSet: `board.reelAt(cell)` hands you the reel to `spin()` / `skipSpin()` it on its own, and `board.symbolAt(cell)` reads the live symbol inside it.', links: [{ label: 'Recipe: Hold & Win — drive each cell on its own', href: '/recipes/hold-and-win-cell-control/' }] },
  'hw-021': { en: '`board.skip()` slams every in-flight cell to its landed position and fires `feature:skip`; gate your own flights / collect on that signal to cut them short, and treat `feature:end` as the single "all done" event.', links: [{ label: 'Recipe: Hold & Win — skip the whole feature', href: '/recipes/hold-and-win-skip/' }] },
  'coins-001': { en: 'Use the shared `CoinSymbol` with `coinValue(amount)` (or your own text) to render the amount on the coin face.', links: [{ label: 'Recipe: Hold & Win — collector', href: '/recipes/hold-and-win-collector/' }] },
  'coins-002': { en: 'Render the amount with a PixiJS `BitmapText` in a gold digit font and format it with `value.toFixed(2)`.', links: [{ label: 'Recipe: Hold & Win — Spine coins', href: '/recipes/hold-and-win-spine/' }] },
  'coins-003': { en: 'Fit the text by font size to a fraction of the coin width, so short values read big and long ones shrink.', links: [{ label: 'Recipe: Hold & Win — Spine coins', href: '/recipes/hold-and-win-spine/' }] },
  'coins-004': { en: 'Carry the value in `coin.data` (the `HwCoin` payload) or a pin payload — the id stays art-only.', links: [{ label: 'Recipe: Value-carrying coin', href: '/recipes/value-coin-pin/' }] },
  'coins-006': { en: 'Land the coin showing the tier word, then on `coin:locked` play the reveal animation that spins it and settles on the money face.', links: [{ label: 'Recipe: Hold & Win — Spine coins', href: '/recipes/hold-and-win-spine/' }] },
  'coins-007': { en: 'The plaques are game-layer UI — render them above the board and flash them on `coin:locked` by `coin.data.kind`.', links: [{ label: 'Recipe: Hold & Win — Spine coins', href: '/recipes/hold-and-win-spine/' }] },
  'coins-008': { en: 'In the `coin:locked` handler, read `coin.data.kind` and play that plaque\'s win animation.', links: [{ label: 'Recipe: Hold & Win — Spine coins', href: '/recipes/hold-and-win-spine/' }] },
  'coins-009': { en: 'On `feature:end`, sum the `board.lockedCoins` data values and roll the total up in your counter.', links: [{ label: 'Recipe: Hold & Win — collector', href: '/recipes/hold-and-win-collector/' }] },
  'coins-011': { en: 'Spawn a clone at `board.cellCenter(coin.cell)` and `bezierFly(clone, from, to, { lean: \'up\' })` into the collector.', links: [{ label: 'Recipe: Hold & Win — collector', href: '/recipes/hold-and-win-collector/' }] },
  'coins-012': { en: 'Increment the collector total in the `bezierFly().then(...)` arrival callback.', links: [{ label: 'Recipe: Hold & Win — collector', href: '/recipes/hold-and-win-collector/' }] },
  'coins-013': { en: 'On its lock, iterate `board.lockedCoins` and bump each value in your game state, flying a token to each coin — the board stays value-agnostic.', links: [{ label: 'Recipe: Hold & Win — payer / doubler coin', href: '/recipes/hold-and-win-payer-coin/' }] },
  'coins-014': { en: 'Same pattern: walk the locked coins and rewrite their values on lock (e.g. `value *= 2`), then refresh the labels from your data.', links: [{ label: 'Recipe: Hold & Win — payer / doubler coin', href: '/recipes/hold-and-win-payer-coin/' }] },
  'coins-015': { en: 'Use `coinWaves(coins, \'by-row\' | \'by-col\')` to order the sweep and `bezierFly` each value into the collector cell, optionally trailed by particle streams.', links: [{ label: 'Recipe: Hold & Win — collector with particles', href: '/recipes/hold-and-win-collector-particles/' }] },
  'coins-016': { en: 'Swap the coin\'s id/data in place with `board.symbolAt(cell)` (or `reelSet.setSymbolAt`) and repaint the label, without disturbing the rest of the grid.', links: [{ label: 'Recipe: Hold & Win — upgrade a coin in place', href: '/recipes/hold-and-win-upgrade-coin/' }] },
  'coins-017': { en: '`board.cellCenter(cell)` gives the start; `bezierFly` to your meter\'s screen position with `arriveScale` to shrink it in.', links: [{ label: 'Recipe: Hold & Win — fly to a feature meter', href: '/recipes/hold-and-win-meter/' }] },
  'coins-018': { en: 'Send a trail sprite or particle along the same `bezierFly` path instead of a coin clone — the board only hands out geometry.', links: [{ label: 'Recipe: Hold & Win — collector', href: '/recipes/hold-and-win-collector/' }] },
  'coins-019': { en: 'Tween a `{ v }` counter from 0 to the value in your `cell:landed` / `coin:locked` handler, rewriting the label every frame, then pop the fitted final amount in.', links: [{ label: 'Recipe: Hold & Win — count-up coin', href: '/recipes/hold-and-win-countup-coin/' }] },
  'coins-020': { en: 'Land it blank, then scroll a masked strip of candidate values inside the coin and ease it onto the revealed number, driven from `coin:locked`.', links: [{ label: 'Recipe: Hold & Win — mystery value coin', href: '/recipes/hold-and-win-mystery-coin/' }] },
  'coins-021': { en: '`coinWaves(board.lockedCoins, \'by-col\')` (also `\'by-row\'` / `\'sequence\'` / `\'all\'` / `{ chunk }`) groups the flights into waves.', links: [{ label: 'Recipe: Hold & Win — collector', href: '/recipes/hold-and-win-collector/' }] },
  'coins-022': { en: '`bezierFly(..., { lean: \'up\' | \'down\' | \'in\' | \'out\', curvature })` bends the arc; `around` sets the in/out reference point.', links: [{ label: 'Recipe: Hold & Win — collector', href: '/recipes/hold-and-win-collector/' }] },
  'coins-023': { en: 'Pass an explicit `control` point to `bezierFly` (computed per coin index) to aim the flight at a specific feature meter.', links: [{ label: 'Recipe: Hold & Win — collector', href: '/recipes/hold-and-win-collector/' }] },
  'coins-024': { en: 'Keep the value in `coin.data` and attach the overlay as a child of the symbol\'s `view`; on an in-place swap re-attach it from `data` (the new instance has a fresh view), and on a flight rebuild it onto the flying clone from the same `data`.', links: [{ label: 'Recipe: Hold & Win — overlay survives swaps and rides flights', href: '/recipes/hold-and-win-sticky-overlay/' }] },
  'anim-001': { en: 'Call `playWin()` on the symbol — `reelSet.getReel(col).getSymbolAt(row).playWin()`.', links: [{ label: 'Guide: Win animations', href: '/guides/win-animations/' }] },
  'anim-002': { en: 'Start an idle/breathing loop in the symbol\'s `onActivate`; `SpineReelSymbol` loops its `idle` animation by default.', links: [{ label: 'Recipe: Big symbols with Spine', href: '/recipes/spine-big-symbols/' }] },
  'anim-003': { en: 'Play it from `onReelLanded`, or use `SpineReelSymbol`\'s `autoPlayLanding` + `playLanding()`.', links: [{ label: 'Recipe: Big symbols with Spine', href: '/recipes/spine-big-symbols/' }] },
  'anim-005': { en: 'Swap to the higher id in place with `setSymbolAt`, playing a transition tween in the old symbol\'s view first.', links: [{ label: 'Recipe: Symbol transform', href: '/recipes/symbol-transform/' }] },
  'anim-006': { en: 'Land mystery placeholders, then pin them all to one random id with `{ turns: \'eval\' }` so they reveal together and clear next spin.', links: [{ label: 'Recipe: Mystery reveal (CellPin)', href: '/recipes/mystery-reveal-pin/' }] },
  'anim-007': { en: 'Park the one-shot just before its end with `timeScale = 0` so it never completes and holds the last frame — the shared `freezeAtEnd` helper does exactly this.', links: [{ label: 'Recipe: Hold & Win — Spine coins', href: '/recipes/hold-and-win-spine/' }] },
  'anim-008': { en: 'Reach the skeleton via `SpineReelSymbol`\'s `.spine` getter and call `spine.state.setAnimation(0, name, loop)`.', links: [{ label: 'Recipe: Hold & Win — Spine coins', href: '/recipes/hold-and-win-spine/' }] },
  'anim-009': { en: '`await symbol.playWin()` / `playLanding()` / `playOut()` resolve when the one-shot finishes.', links: [{ label: 'Guide: Win animations', href: '/guides/win-animations/' }] },
  'anim-010': { en: 'Override `playDestroy(opts)` per symbol class — Spine plays a `disintegration` track, a sprite swaps to a shatter; the default is a scale/spin/fade implode.', links: [{ label: 'Recipe: Remove symbol', href: '/recipes/remove-symbol/' }] },
  'anim-011': { en: '`playDestroy(opts)` honours `opts.signal`; on a slam, abort it and snap the view to the destroyed pose.', links: [{ label: 'Recipe: Slam-stop', href: '/recipes/slam-stop/' }] },
  'anim-012': { en: 'On the triggering event (e.g. `coin:locked` or a win), call a method on the neighbour symbol\'s `view` to shake it.', links: [{ label: 'Recipe: Hold & Win — collector', href: '/recipes/hold-and-win-collector/' }] },
  'anim-013': { en: 'Track a per-symbol charge count in your state, advance its animation each win, and activate when it hits the threshold.' },
  'anim-014': { en: 'Call `driveGsapWithTicker(app.ticker)` once so GSAP advances off the Pixi ticker (and survives hidden tabs).', links: [{ label: 'Guide: Win animations', href: '/guides/win-animations/' }] },
  'chars-001': { en: 'It is a normal PixiJS display object — add your character `Container` to the stage above the `ReelSet`; the engine does not own it.' },
  'chars-003': { en: 'Resolve the `bezierFly` promise on arrival and play the character\'s reaction in the `.then(...)`.', links: [{ label: 'Recipe: Hold & Win — collector', href: '/recipes/hold-and-win-collector/' }] },
  'chars-004': { en: 'On collect, walk the money-symbol cells and `bezierFly` each value into the character; the board only gives you `cellCenter` + the payloads.', links: [{ label: 'Recipe: Hold & Win — collector', href: '/recipes/hold-and-win-collector/' }] },
  'chars-005': { en: '`bezierFly` the value clone to the character\'s position and add it to your running total in the arrival callback.', links: [{ label: 'Recipe: Hold & Win — collector', href: '/recipes/hold-and-win-collector/' }] },
  'chars-006': { en: 'Tween the character along the cell centers from `getCellBounds` / `cellCenter`, stopping on each.', links: [{ label: 'Recipe: Cell bounds', href: '/recipes/cell-bounds/' }] },
  'chars-007': { en: 'Tween the object to the target cell\'s `getCellBounds`, then clear those cells with `destroySymbols` / `setSymbolAt`.', links: [{ label: 'Recipe: Remove symbol', href: '/recipes/remove-symbol/' }] },
  'chars-008': { en: 'Read both cells\' geometry from `getCellBounds`, fly an effect between them, and swap the target via `setSymbolAt` or a pin.', links: [{ label: 'Recipe: Collector symbol', href: '/recipes/collector-symbol-pin/' }] },
  'chars-009': { en: 'On the Hold & Win board, coordinate persistent feature symbols from your lock handler — walk `board.lockedCoins`, read each via `symbolAt(cell)`, and act across cells (absorb, boost, move).', links: [{ label: 'Recipe: Collector symbol', href: '/recipes/collector-symbol-pin/' }] },
  'chars-010': { en: 'The helper tweens to a fixed point, so recompute the target each frame in your own update (or re-issue `bezierFly`) as the character moves.', links: [{ label: 'Recipe: Hold & Win — collector', href: '/recipes/hold-and-win-collector/' }] },
  'chars-011': { en: '`coinWaves(items, \'sequence\')` plus a per-item `delay` on `bezierFly` stagger the throws to arrive one after another.', links: [{ label: 'Recipe: Hold & Win — collector', href: '/recipes/hold-and-win-collector/' }] },
  'chars-012': { en: 'Scale the character\'s view up per collected coin in your collect callback — it is game-layer state.', links: [{ label: 'Recipe: Hold & Win — collector', href: '/recipes/hold-and-win-collector/' }] },
  'triggers-001': { en: 'Detect the scatter count from the grid regardless of position in your win logic; the engine does not evaluate scatters.' },
  'triggers-002': { en: 'Scan `reelSet.getVisibleGrid()` for the scatter id across all cells.', links: [{ label: 'Recipe: Cell bounds', href: '/recipes/cell-bounds/' }] },
  'triggers-003': { en: 'Count the coin symbols in the result and call `board.enter(...)` when the count meets your threshold.', links: [{ label: 'Recipe: Hold & Win respin', href: '/recipes/hold-and-win/' }] },
  'triggers-004': { en: 'Use one id and treat it as both — your trigger logic counts it, and it also lands as a coin in the board\'s seed.', links: [{ label: 'Recipe: Hold & Win respin', href: '/recipes/hold-and-win/' }] },
  'triggers-005': { en: 'With 5 in and a 6th possible, `setAnticipation` on the deciding reel for the tease.', links: [{ label: 'Recipe: Near-miss', href: '/recipes/near-miss/' }] },
  'triggers-006': { en: 'On each scatter land, `bezierFly` it to your trigger counter and bump the count.', links: [{ label: 'Recipe: Hold & Win — collector', href: '/recipes/hold-and-win-collector/' }] },
  'triggers-007': { en: 'Detect the trigger, play your celebration, then swap to the feature (hide base, show the feature display).', links: [{ label: 'Recipe: Feature mode swap', href: '/recipes/feature-mode-swap/' }] },
  'triggers-008': { en: 'Award the scatter pay and enter free spins from the same detected scatters — both are your game logic over one result.' },
  'triggers-009': { en: 'Branch in your trigger logic on which scatter set landed and enter the matching feature.', links: [{ label: 'Recipe: Feature mode swap', href: '/recipes/feature-mode-swap/' }] },
  'triggers-010': { en: 'Pick the spin count from the scatter total in your code before entering the feature.' },
  'fs-001': { en: 'Count scatters in the result and enter free spins in your game logic; the engine reports the grid via `setResult` / events.', links: [{ label: 'Recipe: Feature mode swap', href: '/recipes/feature-mode-swap/' }] },
  'fs-002': { en: 'Toggle a `FrameMiddleware` (or show a second ReelSet) to switch strips/art at runtime with no rebuild.', links: [{ label: 'Recipe: Feature mode swap', href: '/recipes/feature-mode-swap/' }] },
  'fs-003': { en: 'Track the counter in your game state and update the HUD; the engine just spins on demand.' },
  'fs-004': { en: 'Detect the retrigger in the feature result and add to your counter — game-layer bookkeeping.' },
  'fs-005': { en: 'Pin them with a long or `\'permanent\'` TTL so they survive every free spin.', links: [{ label: 'Recipe: Sticky wild (CellPin)', href: '/recipes/sticky-wild-pin/' }] },
  'fs-006': { en: 'Pick the id at feature start and pin its column to expand each spin (the expanding-wild pattern).', links: [{ label: 'Recipe: Expanding wild (CellPin)', href: '/recipes/expanding-wild-pin/' }] },
  'fs-007': { en: 'Spin a feature ReelSet built with different `.weights(...)`, or swap weights by toggling a `FrameMiddleware`.', links: [{ label: 'Recipe: Feature mode swap', href: '/recipes/feature-mode-swap/' }] },
  'fs-008': { en: 'Build the "you won X" screen in your UI layer; the shared `roundBus` win total feeds it.' },
  'fs-009': { en: 'Keep the meter in your state, apply it to wins, and persist it across the feature yourself.', links: [{ label: 'Recipe: Cascade 6×5', href: '/recipes/cascade-6x5/' }] },
  'fs-010': { en: 'Hide the feature display, re-show the base ReelSet, and restore your saved pre-feature state.', links: [{ label: 'Recipe: Feature mode swap', href: '/recipes/feature-mode-swap/' }] },
  'fs-011': { en: 'Wire a button that skips the trigger and calls your enter-feature path directly — pure game logic.' },
  'fs-012': { en: 'Run the gamble in your UI and set the final spin count before entering — outside the engine.' },
  'bonusgames-001': { en: 'Attach pointer events to cells via `getCellBounds` hit areas and reveal prizes on click.', links: [{ label: 'Recipe: Cell hit areas', href: '/recipes/cell-hit-areas/' }] },
  'bonusgames-002': { en: 'Same cell hit-areas — reveal each prize in its click handler.', links: [{ label: 'Recipe: Cell hit areas', href: '/recipes/cell-hit-areas/' }] },
  'bonusgames-003': { en: 'A wheel is a standalone PixiJS widget, not a reel feature — build it in your game layer.' },
  'bonusgames-004': { en: 'Tween the wheel rotation with a GSAP `back.out` ease to settle the pointer — game-layer.' },
  'bonusgames-005': { en: 'A gamble / double-up is a standalone screen in your UI; the reel engine is not involved.' },
  'bonusgames-006': { en: 'A prize ladder is a game-layer mini-game — build the ladder UI and its collect/gamble logic yourself.' },
  'bonusgames-007': { en: 'Cell hit-areas plus your own pick logic tallying matches until three of a kind.', links: [{ label: 'Recipe: Cell hit areas', href: '/recipes/cell-hit-areas/' }] },
  'bonusgames-008': { en: 'Reveal it with your own widget/animation and feed the result into your win math.' },
  'bonusgames-009': { en: 'Tween a token between cells using `getCellBounds` positions; the board-game logic is yours.', links: [{ label: 'Recipe: Cell bounds', href: '/recipes/cell-bounds/' }] },
  'bonusgames-010': { en: 'Sum the picks in your state and show the total in your UI.' },
  'meters-001': { en: 'Render the meter as your own PixiJS/HTML widget above the board; the engine does not own the HUD.' },
  'meters-002': { en: 'Drive it from win events (or the shared `roundBus`) — increment on a win, reset on a dry spin in your handler.' },
  'meters-003': { en: 'Track the level in the symbol\'s pin payload and advance it each win.', links: [{ label: 'Recipe: Multiplier wild (CellPin)', href: '/recipes/multiplier-wild-pin/' }] },
  'meters-004': { en: 'A progress bar is game-layer — fill it from your win events and trigger the feature at 100%.' },
  'meters-005': { en: '`bezierFly` the value to the meter\'s screen position with `arriveScale` and bump it in the arrival callback.', links: [{ label: 'Recipe: Hold & Win — fly to a feature meter', href: '/recipes/hold-and-win-meter/' }] },
  'meters-006': { en: 'A progressive value comes from your server feed; animate the ticking number in your UI.' },
  'meters-007': { en: 'Aggregate collected coins in your state via `coin:locked` / collect callbacks and show the total.', links: [{ label: 'Recipe: Value-carrying coin', href: '/recipes/value-coin-pin/' }] },
  'meters-008': { en: 'Multiply the win in your math layer; the engine presents whatever cells/values you give it.' },
  'meters-009': { en: 'Treat the server value as the source of truth and reconcile the displayed meter to it on each response.' },
  'meters-010': { en: 'Pin the multiplier to its cell with a payload so it persists and stacks by position.', links: [{ label: 'Recipe: Positional multiplier (CellPin)', href: '/recipes/positional-multiplier-pin/' }] },
  'audio-001': { en: 'Listen for `spin:reelLanded` (or `spin:stopping`) and play the stop sound.', links: [{ label: 'Guide: Spin lifecycle', href: '/guides/spin-lifecycle/' }] },
  'audio-002': { en: 'Play it in the `cell:landed` / `coin:locked` handler — they fire in landing (stagger) order.', links: [{ label: 'Recipe: Hold & Win respin', href: '/recipes/hold-and-win/' }] },
  'audio-003': { en: 'Start or raise it when you call `setAnticipation`; drive the layers from your audio engine.' },
  'audio-004': { en: 'Duck the music in your audio layer when the win roll-up starts (e.g. on `win:start`).' },
  'audio-005': { en: 'Ramp the playbackRate of the count-up sound in your audio code as the total climbs.' },
  'audio-006': { en: 'Crossfade tracks in your audio engine on the feature swap; the engine just signals the mode change.', links: [{ label: 'Recipe: Feature mode swap', href: '/recipes/feature-mode-swap/' }] },
  'audio-007': { en: 'Fire `navigator.vibrate(...)` in your `coin:locked` / `board:full` handler.' },
  'audio-008': { en: 'Add a Spine animation event and play the sound from the skeleton\'s event listener via the `.spine` getter.', links: [{ label: 'Recipe: Hold & Win — Spine coins', href: '/recipes/hold-and-win-spine/' }] },
  'audio-009': { en: 'Stop your audio in the same teardown that hides the feature / calls `board.destroy()`.' },
  'audio-010': { en: 'On `skipSpin()`, re-cue or shorten the landing sound — `skip:completed` marks the slammed stop.', links: [{ label: 'Recipe: Slam-stop', href: '/recipes/slam-stop/' }] },
  'ui-001': { en: 'On tap, `spin()` if idle, else `skipSpin()` (or `requestSkip()` if the result has not arrived yet).', links: [{ label: 'Recipe: Slam-stop', href: '/recipes/slam-stop/' }] },
  'ui-002': { en: 'Disable the button on `spin:start` and re-enable when the `spin()` promise resolves (`spin:complete`).' },
  'ui-003': { en: 'Bet and balance live in your game/UI state; the engine does not track money.' },
  'ui-004': { en: 'Loop `await reelSet.spin()` N times with your own stop conditions.' },
  'ui-005': { en: 'Subscribe your HUD to the typed `reelSet.events` / `board.events` — they are the single source of truth.', links: [{ label: 'Recipe: Hold & Win respin', href: '/recipes/hold-and-win/' }] },
  'ui-006': { en: 'Position your text at the center of `reelSet.getCellBounds(col, row)` (or `board.cellCenter`).', links: [{ label: 'Recipe: Cell bounds', href: '/recipes/cell-bounds/' }] },
  'ui-007': { en: '`reelSet.getCellBounds(col, row)` returns the pixel rect to align any overlay exactly.', links: [{ label: 'Recipe: Cell bounds', href: '/recipes/cell-bounds/' }] },
  'ui-008': { en: 'Set each cell\'s `hitArea` / pointer events from `getCellBounds`.', links: [{ label: 'Recipe: Cell hit areas', href: '/recipes/cell-hit-areas/' }] },
  'ui-009': { en: 'Render HUD text at device resolution (high `resolution`) or keep it in a non-scaled HTML/overlay layer.' },
  'ui-010': { en: 'Bind it to the `respins:changed` event / `board.respinsLeft`.', links: [{ label: 'Recipe: Hold & Win respin', href: '/recipes/hold-and-win/' }] },
  'ui-011': { en: 'Draw the background in your scene per mode; the board renders on top of whatever you provide.', links: [{ label: 'Recipe: Hold & Win — Spine coins', href: '/recipes/hold-and-win-spine/' }] },
  'bet-001': { en: 'Both are your evaluation choice — the engine lands a grid; you evaluate lines or ways over it.', links: [{ label: 'Guide: MultiWays', href: '/guides/multiways/' }] },
  'bet-002': { en: 'Bet level lives in your game state; pass it to the server and scale values yourself.' },
  'bet-003': { en: 'Multiply the coin `data.value` by the bet in your code before displaying it.', links: [{ label: 'Recipe: Value-carrying coin', href: '/recipes/value-coin-pin/' }] },
  'bet-004': { en: 'Build a paytable screen from your registered symbol ids and pays — it is UI, not an engine feature.' },
  'bet-005': { en: 'Draw line overlays with `getCellBounds`; highlighting is your render layer.', links: [{ label: 'Recipe: Paylines (events only)', href: '/recipes/paylines-events-only/' }] },
  'bet-006': { en: 'Recompute ways as the product of row counts on `shape:changed` / `adjust:complete`.', links: [{ label: 'Guide: MultiWays', href: '/guides/multiways/' }] },
  'bet-007': { en: 'Compute the buy-feature price from the current bet in your game logic.' },
  'bet-008': { en: 'Disable the bet control in your UI for the feature\'s duration.' },
  'layout-001': { en: 'Lay out your scene per orientation and scale/position the `ReelSet` Container accordingly.' },
  'layout-002': { en: 'Scale `reelSet` to the safe-area box and recompute on resize.' },
  'layout-003': { en: 'Reposition your HUD in your resize handler; the engine exposes the board\'s size, the layout is yours.' },
  'layout-004': { en: 'Position the side panels and the `reelSet` Container around the center in your layout code.', links: [{ label: 'Recipe: Hold & Win — Spine coins', href: '/recipes/hold-and-win-spine/' }] },
  'layout-005': { en: 'Position the meter relative to `reelSet.y` / its bounds.', links: [{ label: 'Recipe: Cell bounds', href: '/recipes/cell-bounds/' }] },
  'layout-006': { en: 'Animate the `ReelSet` / reel containers in with GSAP on load — game-layer choreography.' },
  'layout-007': { en: 'Play a wipe in your scene during the mode swap (hide base, show feature).', links: [{ label: 'Recipe: Feature mode swap', href: '/recipes/feature-mode-swap/' }] },
  'layout-008': { en: 'Tween the reel containers out on exit before calling `destroy()`.' },
  'layout-009': { en: 'Keep the background full-bleed and the `ReelSet` at a fixed size centered on top.' },
  'layout-010': { en: 'Flip your scene layout for RTL in your code; the engine has no locale awareness.' },
  'perf-001': { en: 'The engine already pools symbols via `ObjectPool`, recycling instances instead of recreating them each spin.' },
  'perf-002': { en: '`.poolCapacity(maxPerSymbol)` caps how many of each symbol the pool keeps.' },
  'perf-003': { en: '`reelSet.destroy()` disposes the reels, pools, masks and ticker refs — every subsystem implements `Disposable`.' },
  'perf-004': { en: 'Use `SharedRectMaskStrategy` so one mask clips the whole board instead of one mask per cell.', links: [{ label: 'Recipe: Big symbols (N×M)', href: '/recipes/big-symbols-mxn/' }] },
  'perf-005': { en: '`maskStrategy(new SharedRectMaskStrategy())` clips many cells with a single mask.' },
  'perf-006': { en: 'Drive everything off one `app.ticker` and `driveGsapWithTicker` so tweens do not accumulate; pooling keeps allocations flat.' },
  'perf-007': { en: 'Call `destroy()` on each sub-ReelSet — for a Hold & Win board, `board.destroy()` tears down all its cells at once.', links: [{ label: 'Recipe: Hold & Win respin', href: '/recipes/hold-and-win/' }] },
  'perf-008': { en: 'Kill the symbol\'s tweens in `onDeactivate` / `stopAnimation`; the one-shot `playWin` etc. settle their promises on recycle.', links: [{ label: 'Guide: Win animations', href: '/guides/win-animations/' }] },
  'perf-009': { en: 'Cache one Spine instance per id (as `SpineReelSymbol` does) and reuse it across swaps instead of recreating skeletons.', links: [{ label: 'Recipe: Big symbols with Spine', href: '/recipes/spine-big-symbols/' }] },
  'perf-010': { en: 'Preload the feature atlas/skeletons (e.g. `Assets.load`) before the mode swap so it has no hitch.', links: [{ label: 'Recipe: Feature mode swap', href: '/recipes/feature-mode-swap/' }] },
  'debug-001': { en: '`enableDebug(reelSet)`, then `window.__PIXI_REELS_DEBUG.snapshot()` returns a serializable state object (no PixiJS types).', links: [{ label: 'Guide: Debugging', href: '/guides/debugging/' }] },
  'debug-002': { en: '`__PIXI_REELS_DEBUG.grid()` (or `debugGrid()`) prints an ASCII table of the visible symbols.', links: [{ label: 'Guide: Debugging', href: '/guides/debugging/' }] },
  'debug-003': { en: '`__PIXI_REELS_DEBUG.trace()` logs every domain event as it fires.', links: [{ label: 'Guide: Debugging', href: '/guides/debugging/' }] },
  'debug-004': { en: '`__PIXI_REELS_DEBUG.log()` shows `isSpinning` and per-reel state so you can see which reel never landed.', links: [{ label: 'Guide: Debugging', href: '/guides/debugging/' }] },
  'debug-005': { en: '`CheatEngine` + `holdAndWinProgress(coin, 1)` guarantees a coin every spin for a screenshot.', links: [{ label: 'Guide: Cheats & testing', href: '/guides/cheats-and-testing/' }] },
  'debug-006': { en: 'Inject a fixed `.rng(seed)` and `setResult` a known grid; pure-logic tests need no renderer.', links: [{ label: 'Guide: Cheats & testing', href: '/guides/cheats-and-testing/' }] },
  'debug-007': { en: 'The engine\'s logic modules are pure and testable without a canvas; use the `pixi-reels/testing` entry.', links: [{ label: 'Guide: Cheats & testing', href: '/guides/cheats-and-testing/' }] },
  'debug-008': { en: 'Wire `CheatEngine` (`forceGrid` / `forceScatters` / `forceCell` / `holdAndWinProgress`) to UI toggles.', links: [{ label: 'Guide: Cheats & testing', href: '/guides/cheats-and-testing/' }] },
  'debug-009': { en: '`startRecording()` / `getFrames()` capture a spin\'s frames; replay them to reproduce a bug.', links: [{ label: 'Guide: Debugging', href: '/guides/debugging/' }] },
  'debug-010': { en: 'Assert against `reelSet.getVisibleGrid()` (or `SpinResult.symbols`).', links: [{ label: 'Guide: Cheats & testing', href: '/guides/cheats-and-testing/' }] },
  'integ-001': { en: 'Map each server response to `ColumnTarget[]` and feed `setResult` while the spin is pending.', links: [{ label: 'Recipe: Classic 5×3', href: '/recipes/classic-5x3/' }] },
  'integ-002': { en: 'Keep all payout math server-side; the engine only renders the grid and fires presentation events.' },
  'integ-003': { en: 'Call `spin()` immediately, then `setResult(grid)` when the server replies — the stop sequence lands on it.', links: [{ label: 'Guide: Spin lifecycle', href: '/guides/spin-lifecycle/' }] },
  'integ-004': { en: 'Persist feature state server-side and replay it (e.g. `board.enter(...)` with the saved coins) on reload.', links: [{ label: 'Recipe: Hold & Win respin', href: '/recipes/hold-and-win/' }] },
  'integ-005': { en: 'Format values with `Intl.NumberFormat` in your UI; the engine treats values as opaque data.' },
  'integ-006': { en: 'Translate the server\'s symbol scheme to your registered ids when building the `ColumnTarget[]`.' },
  'integ-007': { en: 'Drive each step with an `await` (e.g. `board.respin(round.hits)` per round) against the server\'s per-step response.', links: [{ label: 'Recipe: Hold & Win respin', href: '/recipes/hold-and-win/' }] },
  'integ-008': { en: 'Only ever render what `setResult` / the server says; never compute outcomes client-side.' },
  'integ-009': { en: 'Reconcile to the server state on each response and re-`setResult` / `setSymbolAt` if the display drifted.' },
  'integ-010': { en: 'Re-inject the recorded seed + result for an exact reproduction; the debug recorder captures frames as evidence.', links: [{ label: 'Guide: Debugging', href: '/guides/debugging/' }] },
};

// Attach answers + links onto their questions at module load.
for (const group of FAQ) {
  for (const q of group.questions) {
    const a = ANSWERS[q.id];
    if (!a) continue;
    q.answer = { en: a.en };
    if (a.links) q.links = a.links;
  }
}

export type FaqQuestionResolved = FaqQuestion & { group: string };

/** Flat list of every question (answer merged in), for search / indexing. */
export const FAQ_QUESTIONS: FaqQuestionResolved[] = FAQ.flatMap((g) =>
  g.questions.map((q) => ({ ...q, group: g.id })),
);

/** Lookup a single resolved question by id. */
export const FAQ_BY_ID: Record<string, FaqQuestionResolved> = Object.fromEntries(
  FAQ_QUESTIONS.map((q) => [q.id, q]),
);

/** Only the answered questions — these get their own `/faq/<id>/` page. */
export const FAQ_ANSWERED: FaqQuestionResolved[] = FAQ_QUESTIONS.filter((q) => q.answer);

/** Group id → its display title, for labels on the index and question pages. */
export const FAQ_GROUP_TITLE: Record<string, FaqGroup['title']> = Object.fromEntries(
  FAQ.map((g) => [g.id, g.title]),
);

/** Total question count — handy for a page header ("300+ questions"). */
export const FAQ_COUNT = FAQ_QUESTIONS.length;

/** How many have answers so far. */
export const FAQ_ANSWERED_COUNT = FAQ_ANSWERED.length;
